module top_module (
    input [1:0] ctrl,
    input in0, in1, in2, in3,
    output reg out
);

    always @(*) begin
        case (ctrl)
            2'b00: out = in0;
            2'b01: out = in1;
            2'b10: out = in2;
            2'b11: out = in3;
            default: out = 1'b0;
        endcase
    end

endmodule
